import pool from './deeptrader-backend/config/database.js';

const statements = [
  "DROP TRIGGER IF EXISTS trigger_create_paper_balance ON exchange_accounts",
  "DROP FUNCTION IF EXISTS create_paper_balance_on_account_insert()"
];

try {
  for (const stmt of statements) {
    await pool.query(stmt);
    console.log('APPLIED_SQL', stmt);
  }
  await pool.end();
  console.log('OK');
} catch (e) {
  console.error('MIGRATION_ERROR', e && e.message ? e.message : String(e));
  try { await pool.end(); } catch {}
  process.exit(1);
}
